---@param item GameObject
function LxNodeBase:FindInstanceID(item)
    local map = self._base_instanceIDMap
    if not map then
        return item:GetInstanceID()
    end
    local id = map[item]
    if not id then
        id = item:GetInstanceID()
        map[item] = id
