    end
end

function LxNodeBase:SetImageLanguage(trans, func, isNativeSize, isHideLoad, defaultImgPath, isCountSize)
    if (trans) then
        local img  = LxUiHelper.FindImageCtrl(trans)
        if img and CS.IsValidObject(img.sprite) then
            local curResName = img.sprite.name
            local path = gLGameLanguage:GetResName(curResName)
            local spriteAtlasPath = LxResPathUtil.GetSpriteAtlasPath(path)
            if not spriteAtlasPath then
                return
            end
            if not string.isempty(path) and curResName ~= path then
                self:SetImageImage(img, path, func,  isNativeSize, isHideLoad, defaultImgPath, isCountSize)
            end
        end
    end
end

function LxNodeBase:SetSprite(rootTrans,trans,spriteName,endFunc)
    if not CS.IsValidObject(trans) then
        return
    end
    self:SetSpriteRenderer(trans, spriteName, endFunc)
end

function LxNodeBase:SetSpriteRenderer(trans,imgPath,func)
    if not CS.IsValidObject(trans) then return end
    if string.isempty(imgPath) then return end

    local path = gLGameLanguage:GetResName(imgPath)
    local spriteAtlasPath = LxResPathUtil.GetSpriteAtlasPath(path)
    if not spriteAtlasPath then return end

    local img = trans:GetComponent(typeOfSpriteRenderer)
    if not img then return end

    self:SetImageImage(img, path, func)
end

function LxNodeBase:SetImage(trans, imgPath, func,  isNativeSize, isHideLoad, defaultImgPath, isCountSize)
    if not CS.IsValidObject(trans) then return end
    if (string.isempty(imgPath)) then
        return
    end

    local path = gLGameLanguage:GetResName(imgPath)
    local spriteAtlasPath = LxResPathUtil.GetSpriteAtlasPath(path)
    if not spriteAtlasPath then
        return
    end
    local img = LxUiHelper.FindImageCtrl(trans)
    if not img then return end
    LxNodeBase.SetImageImage(self, img, path, func,  isNativeSize, isHideLoad, defaultImgPath, isCountSize)
end

function LxNodeBase:SetImageImage(img, path, func,  isNativeSize, isHideLoad, defaultImgPath, isCountSize)
    if not img then return end
    local id = self:FindInstanceID(img)
    local sprite = self._ui_images[id]
    if not sprite then
        sprite = require("LApp.component.res.LxSprite"):New(img)
        self._ui_images[id] = sprite
    end
    sprite:SetLoadedCallback(func)
    sprite:SetSprite(path, isNativeSize, isHideLoad, isCountSize)
end


function LxNodeBase:ClearUIStateActors()
    for k,v in pairs(self._ui_state_actors) do
        v:Dispose()
    end
end
function LxNodeBase:SetImageActorState(trans, state)
    if not CS.IsValidObject(trans) then return end
    local actor = trans:GetComponent(typeofYXUIStateActor)
    if not actor then return end
    local instanceId = self:FindInstanceID(actor)
    local stateactor = self._ui_state_actors[instanceId]
    if not stateactor then
        stateactor = require("LApp.component.res.LxStateActor"):New(actor)
        self._ui_state_actors[instanceId] = stateactor
        stateactor:InitLang()
    end
    stateactor:SetImageActorState(state)
end

